+fn eta_label(secs: f64) -> String {
+    if !secs.is_finite() {
+        return "unknown".to_string();
+    }
+    if secs >= 86_400.0 {
+        return format!("{:.1}d", secs / 86_400.0);
+    }
+    if secs >= 3_600.0 {
+        return format!("{:.1}h", secs / 3_600.0);
+    }
+    if secs >= 60.0 {
+        return format!("{:.1}m", secs / 60.0);
+    }
+    format!("{secs:.0}s")
+}
